namespace sv_fc1b10691e084a32b0751de3e12f747a;

public enum Theme
{
    Light,
    Dark,
    System
}

public record ThemeInfo(Theme Theme, string AccentColor)
{
    public static ThemeInfo Default => new(Theme.Light, "#0d6efd");
}

@* Rendered interactive in the layout so it updates immediately when theme changes *@

<span class="badge" style="background-color: @(Theme?.AccentColor ?? "#0d6efd")">
    🎨 @(Theme?.Theme.ToString() ?? "Light")
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }
}

@inject CascadingValueSource<ThemeInfo> ThemeSource

<button class="btn btn-sm btn-outline-secondary" @onclick="Toggle">
    @switch (Theme?.Theme)
    {
        case sv_fc1b10691e084a32b0751de3e12f747a.Theme.Dark:
            <span>🌙 Dark</span>
            break;
        case sv_fc1b10691e084a32b0751de3e12f747a.Theme.System:
            <span>💻 System</span>
            break;
        default:
            <span>☀️ Light</span>
            break;
    }
</button>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private static readonly Theme[] Cycle =
        [sv_fc1b10691e084a32b0751de3e12f747a.Theme.Light,
         sv_fc1b10691e084a32b0751de3e12f747a.Theme.Dark,
         sv_fc1b10691e084a32b0751de3e12f747a.Theme.System];

    private async Task Toggle()
    {
        var current = Theme ?? ThemeInfo.Default;
        var nextIndex = (Array.IndexOf(Cycle, current.Theme) + 1) % Cycle.Length;
        await ThemeSource.NotifyChangedAsync(current with { Theme = Cycle[nextIndex] });
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label">Theme</label>
    <select class="form-select" style="max-width:200px"
            value="@selectedTheme" @onchange="OnThemeChanged">
        <option value="Light">☀️ Light</option>
        <option value="Dark">🌙 Dark</option>
        <option value="System">💻 System</option>
    </select>
</div>

<div class="mb-3">
    <label class="form-label">Accent Color</label>
    <input type="color" class="form-control form-control-color"
           value="@accentColor" @onchange="OnColorChanged" />
</div>

<div class="mt-4 p-3 border rounded" style="border-color: @accentColor !important">
    <strong>Preview:</strong> Theme = @selectedTheme, Accent =
    <span style="color: @accentColor">@accentColor</span>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private string selectedTheme = nameof(sv_fc1b10691e084a32b0751de3e12f747a.Theme.Light);
    private string accentColor = ThemeInfo.Default.AccentColor;

    protected override void OnParametersSet()
    {
        if (Theme is not null)
        {
            selectedTheme = Theme.Theme.ToString();
            accentColor = Theme.AccentColor;
        }
    }

    private async Task OnThemeChanged(ChangeEventArgs e)
    {
        selectedTheme = e.Value?.ToString() ?? selectedTheme;
        await PushUpdate();
    }

    private async Task OnColorChanged(ChangeEventArgs e)
    {
        accentColor = e.Value?.ToString() ?? accentColor;
        await PushUpdate();
    }

    private async Task PushUpdate()
    {
        var theme = Enum.Parse<sv_fc1b10691e084a32b0751de3e12f747a.Theme>(selectedTheme);
        await ThemeSource.NotifyChangedAsync(new ThemeInfo(theme, accentColor));
    }
}

